package com.google.gson.typeadapters;

import java.io.IOException;
import java.text.ParseException;
import java.text.ParsePosition;
import java.util.Calendar;
import java.util.Date;
import java.util.GregorianCalendar;
import java.util.Locale;
import java.util.TimeZone;
import com.google.gson.JsonParseException;
import com.google.gson.TypeAdapter;
import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import com.google.gson.stream.JsonWriter;
public final class UtcDateTypeAdapter extends TypeAdapter<Date>{
@Override
  public Date read(JsonReader in) throws IOException {
    try {
      switch (in.peek()) {
        case NULL:
          in.nextNull();
          return null;
        default:
          String date = in.nextString();
          // Instead of using iso8601Format.parse(value), we use Jackson's date parsing
          // This is because Android doesn't support XXX because it is JDK 1.6
          return parse(date, new ParsePosition(0));
      }
    } catch (ParseException e) {
      throw new JsonParseException(e);
    }
  }
private final TimeZone UTC_TIME_ZONE = TimeZone.getTimeZone("UTC");
private static final String GMT_ID = "GMT";
@Override public void write(JsonWriter out, Date date)
private static String format(Date date, boolean millis, TimeZone tz)
private static void padInt(StringBuilder buffer, int value, int length)
private static Date parse(String date, ParsePosition pos)
private static boolean checkOffset(String value, int offset, char expected)
private static int parseInt(String value, int beginIndex, int endIndex)
}
